# convert hex string to bytes
data = bytes.fromhex(''.join(hex_data.split()))

def read_string(data, offset):
    length = data[offset]
    offset += 1
    string_bytes = data[offset:offset+length]
    string = string_bytes.decode('ascii', errors='ignore')
    offset += length
    return string, offset

def read_int(data, offset):
    val = struct.unpack_from('<I', data, offset)[0]  # little-endian unsigned int
    return val, offset + 4

def read_float(data, offset):
    val = struct.unpack_from('<f', data, offset)[0]  # little-endian float
    return val, offset + 4

offset = 0
parsed = []

# skip header (first 12 bytes)
offset = 12

while offset < len(data):
    try:
        # read string if first byte is reasonable
        if 1 <= data[offset] <= 64:
            op, offset = read_string(data, offset)
            # try to read a parameter as int or float if enough bytes remain
            params = []
            if offset + 4 <= len(data):
                num, offset = read_int(data, offset)
                params.append(num)
            parsed.append({'operation': op, 'params': params})
        else:
            offset += 1
    except Exception as e:
        # avoid infinite loops if data is malformed
        print("Parse error at offset", offset, e)
        break

# print parsed operations
for entry in parsed:
    print(entry)